args.sparql:
SELECT ?stadium ?stadiumLabel WHERE {
  wd:Q329812 p:P119 ?statement .
  ?statement ps:P119 ?stadium .
  ?statement pq:P580 ?startDate .
  OPTIONAL { ?statement pq:P582 ?endDate . }
  FILTER (YEAR(?startDate) <= 2011 && (YEAR(?endDate) >= 2011 || !BOUND(?endDate)))
  ?stadium rdfs:label ?stadiumLabel .
  FILTER (LANG(?stadiumLabel) = 'en')
}

SELECT ?stadium ?stadiumLabel WHERE {
  wd:Q329812 p:P119 ?statement .
  ?statement ps:P119 ?stadium .
  ?statement pq:P580 ?startDate .
  OPTIONAL { ?statement pq:P582 ?endDate . }
  FILTER ( ?startDate <= "2011-12-31T00:00:00Z"^^xsd:dateTime && ( ?endDate >= "2011-01-01T00:00:00Z"^^xsd:dateTime || !BOUND(?endDate) ) )
  ?stadium rdfs:label ?stadiumLabel .
  FILTER (LANG(?stadiumLabel) = 'en')
}

SELECT ?stadium ?stadiumLabel WHERE {
  wd:Q329812 p:P119 ?statement .
  ?statement ps:P119 ?stadium .
  ?statement pq:P580 ?startDate .
  OPTIONAL { ?statement pq:P582 ?endDate . }
  FILTER ( ?startDate <= "2011-12-31"^^xsd:date && ( !BOUND(?endDate) || ?endDate >= "2011-01-01"^^xsd:date ) )
  ?stadium rdfs:label ?stadiumLabel .
  FILTER (LANG(?stadiumLabel) = 'en')
}

SELECT DISTINCT ?stadium ?stadiumLabel WHERE {
  wd:Q329812 wdt:P119 ?stadium .
  ?stadium rdfs:label ?stadiumLabel .
  FILTER (LANG(?stadiumLabel) = 'en')
  FILTER (CONTAINS(LCASE(STR(?stadiumLabel)), 'sporting park'))
}
